sp_header_footer.client_script:
api.controller=function() {
  /* widget controller */
  var c = this;
};

sp_header_footer.css:
.smarthub-footer {
  font-family: 'Inter', sans-serif;
  background-color: #1e293b; /* Very dark slate, contrasting the white portal */
  color: #94a3b8;
  padding: 20px 0;
  margin-top: auto; /* Pushes footer to bottom if page content is short */
  width: 100%;
}

.footer-container {
  max-width: 1600px;
  margin: 0 auto;
  padding: 0 25px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 12px;
}

.footer-left { display: flex; align-items: center; gap: 10px; }
.footer-brand { color: #ffffff; font-weight: 600; font-size: 14px; letter-spacing: -0.3px; }
.footer-version { background-color: #334155; padding: 2px 6px; border-radius: 4px; font-size: 10px; font-weight: 700; color: #cbd5e1; }

.footer-right { display: flex; align-items: center; gap: 10px; font-weight: 500; }
.footer-divider { color: #475569; }

.footer-right a { color: #94a3b8; text-decoration: none; transition: color 0.2s; }
.footer-right a:hover { color: #ffffff; }

/* Responsive */
@media (max-width: 768px) {
  .footer-container { flex-direction: column; gap: 15px; text-align: center; }
}

sp_header_footer.script:
(function() {
    // Dynamically fetch the current year so it never goes out of date
    var gdt = new GlideDateTime();
    data.year = gdt.getYearLocalTime();
})();
